import requests
import pandas as pd
from io import StringIO

LIPIDMAPS_URL = "https://www.lipidmaps.org/ms/rest/ms_search/"

def _get_num_matches(db, mzStr, adducts, tolerance=0.001):
    # Clean m/z string: split by lines, ignore blank lines, strip whitespace, filter non-empty
    lines = [line.strip() for line in mzStr.split('\n') if line.strip() != '']
    if not lines:
        return 0
    cleaned_mzStr = '\n'.join(lines)

    # Clean adducts: split by comma, strip whitespace, remove empty, join back
    adduct_list = [a.strip() for a in adducts.split(',') if a.strip() != '']
    cleaned_adducts = ','.join(adduct_list)

    files = {'file': ('file', StringIO(cleaned_mzStr), 'text/plain')}
    data = {
        'CHOICE': db,
        'ion': cleaned_adducts,
        'tol': str(tolerance),
        'sort': 'DELTA'
    }
    try:
        response = requests.post(LIPIDMAPS_URL, data=data, files=files)
    except:
        raise Exception(
            'Connection error with the database. Please check your network and try again after a few minutes.'
            )
    if len(response.text) == 0:
        return 0
    else:
        matches = pd.read_csv(StringIO(response.text), sep='\t', engine='python', index_col=False)
        if matches.empty:
            return 0
        else:
            try:
                unique_masses = matches['Input Mass'].unique()
            except KeyError:
                unique_masses = matches.iloc[:, 0].unique()
            return len(unique_masses)

def main():
    db = 'GLYCOLIPIDS'
    mz_values = '100.0\n200.0\n300.0'
    adducts = 'M+H,M+Na'
    tolerance = 0.01
    num_matches = _get_num_matches(db, mz_values, adducts, tolerance)
    print(f'Number of unique m/z matches: {num_matches}')

if __name__ == '__main__':
    main()
